// Ambil data langsung dari masing-masing Read node via referensi
// Cara ini lebih reliable daripada tebak-tebak kolom
const addIdx = arr => arr.map((r,i) => ({...r, _row_index: i+2}));

return [{ json: {
  biochar_prod : addIdx($('📥 Read biochar_production').all().map(i=>i.json)),
  bag_prod     : addIdx($('📥 Read bag_production').all().map(i=>i.json)),
  biochar_app  : addIdx($('📥 Read biochar_application').all().map(i=>i.json)),
  bag_app      : addIdx($('📥 Read bag_application').all().map(i=>i.json)),
  loaded_at    : new Date().toISOString(),
}}];

const data = $input.first().json;
const wmap={}, ids=new Set(), bic={}, bam={}, bsum={};
for (const r of data.bag_prod) {
  const bid=String(r.bag_id||''), w=parseFloat(String(r.weight||'').replace(',','.'));
  if(bid){ids.add(bid); bic[bid]=(bic[bid]||0)+1;}
  if(bid&&!isNaN(w)){
    wmap[bid]=w;
    const p=String(r.production_id||'');
    if(p) bsum[p]=(bsum[p]||0)+w;
  }
}
for (const r of data.bag_app) {
  const bid=String(r.bag_id||''), aid=String(r.application_id||'');
  if(bid&&aid){if(!bam[bid])bam[bid]=[]; if(!bam[bid].includes(aid))bam[bid].push(aid);}
}
return [{json:{...data, lookup:{
  bag_prod_weight_map:wmap,
  bag_prod_id_set:[...ids],
  bag_id_count:bic,
  bag_app_map:bam,
  batch_sums:bsum,
}}}];

const payload=$input.first().json, data=payload, lk=payload.lookup;
const today=new Date(); today.setHours(0,0,0,0);
const VALID=['Application-Pure Biochar','Application-Charged Biochar','Sale-Pure Biochar','Sale-Charged Biochar'];
const anomalies=[], fixedBag=JSON.parse(JSON.stringify(data.bag_prod));
const toF=v=>{try{return parseFloat(String(v).replace(',','.'))}catch{return NaN}};
const toD=v=>{try{const d=new Date(v);return isNaN(d)?null:d}catch{return null}};
const empty=v=>v==null||String(v).trim()===''||String(v).toLowerCase()==='nan';
const log=(sh,tp,ds,fi,or,fx,ac,ri)=>({
  Sheet:sh,anomaly_type:tp,description:ds,Field:fi,
  original_value:String(or),suggested_fix:String(fx),action:ac,Record_ID:String(ri),
  detected_at:new Date().toISOString().replace('T',' ').slice(0,19),
  Reviewed_By:'',Resolution:'',Resolved_At:'',
});

// TYPE 1
for(let i=0;i<fixedBag.length;i++){
  const r=fixedBag[i],w=String(r.weight||'');
  if(w.includes(',')){const f=parseFloat(w.replace(',','.'));
    anomalies.push(log('bag_production','TYPE 1',`Comma decimal: "${w}" → ${f}`,'weight',w,f,'AUTO-FIXED → CLEANED',r.bag_id||''));
    fixedBag[i].weight=f;}
}
// TYPE 2
for(const r of fixedBag)for(const f of['weight','co2e_persistent','co2e_100','spc']){const v=toF(r[f]);if(!isNaN(v)&&v<0)anomalies.push(log('bag_production','TYPE 2',`Negative: ${f}=${v}`,f,v,'Requires human review','FLAGGED → VALIDATION_QUEUE',r.bag_id||''));}
for(const r of data.biochar_prod)for(const f of['co2e_persistent','co2e_100','spc']){const v=toF(r[f]);if(!isNaN(v)&&v<0)anomalies.push(log('biochar_production','TYPE 2',`Negative: ${f}=${v}`,f,v,'Requires human review','FLAGGED → VALIDATION_QUEUE',r.activity_id||''));}
// TYPE 3
for(const r of fixedBag)if(empty(r.weight))anomalies.push(log('bag_production','TYPE 3','Missing: weight','weight','','Requires human review','FLAGGED → VALIDATION_QUEUE',r.bag_id||''));
for(const r of data.biochar_prod)if(empty(r['carbon_content_%']))anomalies.push(log('biochar_production','TYPE 3','Missing: carbon_content_%','carbon_content_%','','Requires human review','FLAGGED → VALIDATION_QUEUE',r.activity_id||''));
// TYPE 4
for(const r of data.bag_prod){const b=String(r.bag_id||'');if((lk.bag_id_count[b]||0)>1)anomalies.push(log('bag_production','TYPE 4',`Duplicate bag_id weight=${r.weight}`,'bag_id',b,'Keep first occurrence','FLAGGED → VALIDATION_QUEUE',b));}
// TYPE 5
for(const{name:nm,rows,id} of[{name:'biochar_production',rows:data.biochar_prod,id:'activity_id'},{name:'bag_production',rows:data.bag_prod,id:'bag_id'},{name:'biochar_application',rows:data.biochar_app,id:'activity_id'},{name:'bag_application',rows:data.bag_app,id:'bag_id'}]){
  for(const r of rows){const ts=toD(r.Timestamp);if(ts&&ts>today)anomalies.push(log(nm,'TYPE 5',`Future Timestamp: ${r.Timestamp}`,'Timestamp',String(r.Timestamp),'Requires human review','FLAGGED → VALIDATION_QUEUE',r[id]||''));}}
for(const r of data.biochar_app){
  const ad=toD(r.application_date),ts=toD(r.Timestamp),aid=r.activity_id||'';
  if(ad&&ad>today)anomalies.push(log('biochar_application','TYPE 5',`Future application_date: ${r.application_date}`,'application_date',String(r.application_date),'Requires human review','FLAGGED → VALIDATION_QUEUE',aid));
  if(ad&&ts){const gap=Math.round((ad-ts)/86400000);if(gap>30)anomalies.push(log('biochar_application','TYPE 5',`Suspicious app_date: ${r.application_date} adalah ${gap}h setelah Timestamp ${r.Timestamp}`,'application_date',String(r.application_date),'Konfirmasi ke operator','FLAGGED → VALIDATION_QUEUE',aid));}}
// TYPE 6
for(const r of data.biochar_app){const at=String(r.application_type||'');if(!VALID.includes(at))anomalies.push(log('biochar_application','TYPE 6',`Invalid application_type: "${at}"`,'application_type',at,`Must be one of: ${VALID.join(', ')}`,'FLAGGED → VALIDATION_QUEUE',r.activity_id||''));}
// TYPE 7
const bpids=new Set(lk.bag_prod_id_set);
for(const r of data.bag_app){const b=String(r.bag_id||'');if(b&&!bpids.has(b))anomalies.push(log('bag_application','TYPE 7',`Orphan bag_id: ${b}`,'bag_id',b,'No matching production record','FLAGGED → VALIDATION_QUEUE',b));}
// TYPE 8
for(const r of data.bag_app){const b=String(r.bag_id||''),aw=toF(r.bag_weight),pw=lk.bag_prod_weight_map[b];if(!isNaN(aw)&&pw!==undefined){const d=Math.abs(aw-pw)/pw;if(d>0.05)anomalies.push(log('bag_application','TYPE 8',`Weight disc ${(d*100).toFixed(1)}%: app=${aw.toFixed(2)} vs prod=${pw.toFixed(2)}`,'bag_weight',aw,`prod=${pw.toFixed(2)} kg`,'FLAGGED → VALIDATION_QUEUE',b));}}
// TYPE 9
const bs={};
for(const r of fixedBag){const p=String(r.production_id||''),w=toF(r.weight);if(p&&!isNaN(w))bs[p]=(bs[p]||0)+w;}
for(const r of data.biochar_prod){const p=String(r.activity_id||''),dec=toF(r.biochar_amount_kg),s=bs[p];if(s!==undefined&&!isNaN(dec)){const d=Math.abs(s-dec);if(d>0.01)anomalies.push(log('bag_production','TYPE 9',`Batch sum: sum=${s.toFixed(2)} vs declared=${dec.toFixed(2)} Δ=${d.toFixed(2)}`,'biochar_amount_kg',`sum=${s.toFixed(2)}`,`Declared=${dec.toFixed(2)} kg`,'FLAGGED → VALIDATION_QUEUE',p));}}
// TYPE 10
for(const r of data.bag_app){const b=String(r.bag_id||''),aids=lk.bag_app_map[b]||[];if(aids.length>1)anomalies.push(log('bag_application','TYPE 10',`Bag di ${aids.length} batches: [${aids.sort().join(', ')}]`,'bag_id / application_id',b,'Satu bag hanya boleh di SATU batch','FLAGGED → VALIDATION_QUEUE',b));}

const tc={};for(const a of anomalies)tc[a.anomaly_type]=(tc[a.anomaly_type]||0)+1;
return [{json:{...data, fixed_bag_prod:fixedBag, anomalies, type_counts:tc,
  total_anomalies:anomalies.length,
  new_flags:anomalies.filter(a=>a.action.includes('VALIDATION_QUEUE')).length,
  auto_fixed:anomalies.filter(a=>a.action.includes('AUTO-FIXED')).length,
  run_timestamp:new Date().toISOString().replace('T',' ').slice(0,19),
}}];

const p=$input.first().json, an=p.anomalies, fb=p.fixed_bag_prod;
const sk={'biochar_production':'biochar_prod','bag_production':'bag_prod','biochar_application':'biochar_app','bag_application':'bag_app'};
const fl={biochar_prod:new Set(),bag_prod:new Set(),biochar_app:new Set(),bag_app:new Set()};
for(const a of an){if(a.anomaly_type==='TYPE 1')continue;
  for(const[pr,k]of Object.entries(sk)){if(a.Sheet.startsWith(pr)){const rid=String(a.Record_ID),rows=k==='bag_prod'?fb:p[k];
    for(const r of rows){const id=String(r.bag_id||r.activity_id||'');if(id===rid)fl[k].add(r._row_index);}}}}
const seen=new Set();
for(const r of fb){const b=String(r.bag_id||'');if(seen.has(b))fl.bag_prod.add(r._row_index);else seen.add(b);}
return [{json:{...p, cleaned:{
  biochar_prod:p.biochar_prod.filter(r=>!fl.biochar_prod.has(r._row_index)),
  bag_prod:fb.filter(r=>!fl.bag_prod.has(r._row_index)),
  biochar_app:p.biochar_app.filter(r=>!fl.biochar_app.has(r._row_index)),
  bag_app:p.bag_app.filter(r=>!fl.bag_app.has(r._row_index)),
}}}];

const p=$input.first().json;
const mk=rows=>rows.map(r=>{const{_row_index,...rest}=r;return{...rest,_cleaning_note:'auto-cleaned'};});
return [{json:{...p, write_data:{
  cleaned_prod_batch:mk(p.cleaned.biochar_prod),
  cleaned_bag_prod:mk(p.cleaned.bag_prod),
  cleaned_app_batch:mk(p.cleaned.biochar_app),
  cleaned_bag_app:mk(p.cleaned.bag_app),
}}}];

const p=$input.first().json;
const an=p.anomalies||[], tc=p.type_counts||{};
const fl=an.filter(a=>a.action.includes('VALIDATION_QUEUE'));
const summary=Object.entries(tc).filter(([t])=>t!=='TYPE 1').sort().map(([t,c])=>`${t}: ${c}`).join('
');
const preview=fl.slice(0,5).map(a=>`[${a.anomaly_type}] ${a.Sheet} | ${a.Record_ID}
→ ${a.description}`).join('

');
const more=fl.length>5?`

... dan ${fl.length-5} lainnya`:'';
return [{json:{
  to:'nurimammasri.01@gmail.com',
  subject:`[WasteX] ${p.new_flags||0} anomali baru — ${new Date(p.run_timestamp).toLocaleDateString('id-ID')}`,
  body:`WasteX Pipeline Laporan
==========================
Run: ${p.run_timestamp}
Anomali baru: ${p.new_flags||0}
Auto-fixed: ${p.auto_fixed||0}
Butuh review: ${fl.length}

RINGKASAN:
${summary}

PREVIEW:
${preview}${more}

Buka VALIDATION_QUEUE untuk review.
---
Email otomatis WasteX.`,
}}];

// Ambil cleaned data untuk biochar_production
const p = $('🧹 Build Cleaned Data').first().json;
const rows = p.cleaned.biochar_prod || [];
if (rows.length === 0) return [{ json: { _empty: true } }];
// Return setiap row sebagai item terpisah, tanpa _row_index
return rows.map(r => {
  const { _row_index, ...clean } = r;
  return { json: { ...clean, _cleaning_note: 'auto-cleaned' } };
});

const p = $('🧹 Build Cleaned Data').first().json;
const rows = p.cleaned.bag_prod || [];
if (rows.length === 0) return [{ json: { _empty: true } }];
return rows.map(r => {
  const { _row_index, ...clean } = r;
  return { json: { ...clean, _cleaning_note: 'auto-cleaned' } };
