const p = $('🧹 Build Cleaned Data').first().json;
const rows = p.cleaned.bag_app || [];
if (rows.length === 0) return [{ json: { _empty: true } }];
return rows.map(r => {
  const { _row_index, ...clean } = r;
  return { json: { ...clean, _cleaning_note: 'auto-cleaned' } };
});

const p = $('🔄 Restore After Queue1').first().json;

return [
  {
    json: {
      ...p,
      should_notify: (p.new_flags || 0) > 0
    }
  }
];

const fi = $input.first().json;
const p  = fi._pp ? JSON.parse(fi._pp) : fi;
const an = p.anomalies || [], cl = p.cleaned || {}, ts = p.run_timestamp;

const ct = (sn, t) => an.filter(a => a.Sheet.startsWith(sn) && a.anomaly_type === t).length;

const cfg = [
  { n:'biochar_production',  rk:'biochar_prod', ck:'biochar_prod'  },
  { n:'bag_production',      rk:'bag_prod',      ck:'bag_prod'      },
  { n:'biochar_application', rk:'biochar_app',  ck:'biochar_app'   },
  { n:'bag_application',     rk:'bag_app',       ck:'bag_app'       },
];

return cfg.map(({ n, rk, ck }, i) => {
  const raw  = p[rk]  || [];
  const cln  = cl[ck] || [];
  const sa   = an.filter(a => a.Sheet.startsWith(n));
  const fl   = sa.filter(a => a.anomaly_type !== 'TYPE 1').length;

  const e1=ct(n,'TYPE 1'), e2=ct(n,'TYPE 2'), e3=ct(n,'TYPE 3'), e4=ct(n,'TYPE 4');
  const e5=ct(n,'TYPE 5'), e6=ct(n,'TYPE 6'), e7=ct(n,'TYPE 7'), e8=ct(n,'TYPE 8');
  const e9=ct(n,'TYPE 9'), e10=ct(n,'TYPE 10');

  const acts = [];
  if (e1 > 0) acts.push(`${e1} comma decimal auto-fixed`);
  if (fl > 0) acts.push(`${fl} rows flagged ke VALIDATION_QUEUE`);
  if (raw.length - cln.length > 0) acts.push(`${raw.length - cln.length} rows excluded dari CLEANED`);

  const notes = [];
  if (e9  > 0) notes.push(`TYPE 9 batch sum mismatch: ${e9}`);
  if (e10 > 0) notes.push(`TYPE 10 bag multi-application: ${e10}`);

  return { json: {
    Run_Timestamp             : ts,
    Sheet_Processed           : n,
    Records_In                : raw.length,
    Records_Clean             : cln.length,
    Records_Flagged           : fl,
    Errors_Comma_Decimal      : e1,
    Errors_Negative           : e2,
    Errors_Missing_Critical   : e3,
    Errors_Duplicate_Bag      : e4,
    Errors_Orphan_Bag         : e7,
    Errors_Weight_Discrepancy : e8,
    Errors_Future_Date        : e5,
    Errors_Invalid_Category   : e6,
    Action_Taken              : acts.length ? acts.join('; ') : 'No anomalies — data passed clean',
    Notes                     : notes.join('; '),
    // simpan payload hanya di baris pertama
    _pp                       : i === 0 ? JSON.stringify(p) : '',
  }};
});

// Restore payload utama langsung dari node sebelum split queue
const p = $('🔄 Restore Pipeline Data1').first().json;

return [
  {
    json: p
  }
];

const p = $input.first().json;
const toQ = p.anomalies.filter(a => !a.action.includes('AUTO-FIXED'));

if (toQ.length === 0) {
  return [{ json: { ...p, _skip: true, queued_count: 0 } }];
}

// Simpan payload hanya di _global, tidak ikut ke sheet
const pPayload = JSON.stringify({ ...p, queued_count: toQ.length });

// Return setiap anomali sebagai item terpisah
// Hanya field yang perlu masuk ke VALIDATION_QUEUE
return toQ.map((a, i) => ({
  json: {
    Sheet          : a.Sheet,
    anomaly_type   : a.anomaly_type,
    description    : a.description,
    Field          : a.Field,
    original_value : a.original_value,
    suggested_fix  : a.suggested_fix,
    action         : a.action,
    Record_ID      : a.Record_ID,
    detected_at    : a.detected_at,
    Reviewed_By    : '',
    Resolution     : '',
    Resolved_At    : '',
    // simpan payload di item pertama untuk diambil setelah append
    _pp            : i === 0 ? pPayload : '',
  }
}));

// Semua 4 Write CLEANED sudah selesai
// Ambil pipeline payload dari node Detect yang sudah jalan sebelumnya
const detect  = $('🔍 Detect All 10 Anomaly Types').first().json;
const cleaned = $('🧹 Build Cleaned Data').first().json.cleaned;
return [{ json: { ...detect, cleaned } }];

